const { ApolloServer } = require('apollo-server-express');
const express = require('express');
const { Pool } = require('pg');

// PostgreSQL database connection settings
const dbConfig = {
  user: 'your_username',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
};

// Create a new PostgreSQL pool instance
const pool = new Pool(dbConfig);

// Define the GraphQL schema
const typeDefs = `
  type Author {
    id: ID!
    name: String!
    email: String!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    author: Author!
  }

  type Query {
    posts: [Post!]!
  }
`;

// Define the resolvers
const resolvers = {
  Query: {
    posts: async () => {
      const result = await pool.query('SELECT * FROM posts');
      return result.rows.map((post) => ({
        id: post.id,
        title: post.title,
        content: post.content,
        author: await getAuthor(post.author_id),
      }));
    },
  },
};

// Helper function to fetch an author from the database
const getAuthor = async (id) => {
  const result = await pool.query('SELECT * FROM authors WHERE id = $1', [id]);
  return result.rows[0];
};

// Create a new Apollo Server instance
const app = express();
const server = new ApolloServer({ typeDefs, resolvers });

// Apply security middleware to the Express app
app.use((req, res, next) => {
  // Validate untrusted input (e.g., sanitize user-controlled input)
  req.body = JSON.parse(JSON.stringify(req.body));
  next();
});

server.applyMiddleware({ app });

// Start the server
const port = 4000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});